sql:
SELECT created_by, created_date
FROM configurations
WHERE created_date = (
  SELECT MAX(created_date)
  FROM configurations
);

SELECT configurations.config_id, configurations.setting_name, default_values.value
FROM configurations
INNER JOIN default_values ON configurations.config_id = default_values.config_id;

SELECT config_id, setting_name
FROM configurations
WHERE LENGTH(setting_name) = (
    SELECT MAX(LENGTH(setting_name))
    FROM configurations
);

